/*
 * IoT Device Firmware - Weather Station Node
 * Target: ESP32/Arduino compatible microcontrollers
 * Demonstrates: Device layer implementation per IoT Design Methodology
 * 
 * This code follows Step 7 (Functional View) specification
 * using MQTT protocol for cloud communication
 */

#include <stdio.h>
#include <string.h>
#include <stdlib.h>
#include <time.h>

// ============================================
// HARDWARE ABSTRACTION LAYER (HAL)
// ============================================

/* Simulated hardware registers and functions */
typedef struct {
    int pin_number;
    int analog_value;
    int digital_value;
    int is_initialized;
} SensorPin;

typedef struct {
    char ssid[32];
    char password[64];
    int is_connected;
} WiFiConfig;

// Simulated sensor reading functions
int read_adc_channel(int channel) {
    // In real hardware: return ADC register value
    // Simulated: return random value
    return (rand() % 4096);
}

void delay_ms(int milliseconds) {
    // In real hardware: implement delay
}

// ============================================
// DATA STRUCTURES (Step 4: Information Model)
// ============================================

/* Information Model: JSON schema definition */
typedef struct {
    char sensor_id[32];
    char timestamp[32];
    float temperature;      // Celsius
    float humidity;         // Percentage
    int rain_detected;      // 0 or 1
    float battery_level;    // Voltage
} SensorReading;

typedef struct {
    char device_id[32];
    char firmware_version[16];
    int boot_count;
    int free_heap;
    SensorReading current_reading;
} DeviceStatus;

// ============================================
// SENSOR DRIVERS (Step 7: Physical Devices)
// ============================================

/* DHT22 Temperature & Humidity Sensor Driver */
typedef struct {
    int data_pin;
    float last_temperature;
    float last_humidity;
} DHT22_Sensor;

void DHT22_init(DHT22_Sensor* sensor, int pin) {
    sensor->data_pin = pin;
    sensor->last_temperature = 0.0;
    sensor->last_humidity = 0.0;
    printf("[DHT22] Initialized on GPIO%d\n", pin);
}

int DHT22_read(DHT22_Sensor* sensor) {
    /*
     * Real implementation would use timing-sensitive code
     * to read the DHT22 protocol (single-wire communication)
     */
    // Simulated readings
    sensor->last_temperature = 20.0 + (rand() % 150) / 10.0;  // 20-35°C
    sensor->last_humidity = 40.0 + (rand() % 500) / 10.0;      // 40-90%

    return 0;  // Success
}

/* Rain Drop Sensor Driver */
typedef struct {
    int analog_pin;
    int threshold;
} RainSensor;

void RainSensor_init(RainSensor* sensor, int pin, int threshold) {
    sensor->analog_pin = pin;
    sensor->threshold = threshold;
    printf("[RainSensor] Initialized on ADC channel %d\n", pin);
}

int RainSensor_detect(RainSensor* sensor) {
    int adc_value = read_adc_channel(sensor->analog_pin);
    // Lower ADC = more rain (water conducts)
    return (adc_value < sensor->threshold) ? 1 : 0;
}

// ============================================
// MQTT COMMUNICATION (Step 5: Data Ingestion Service)
// ============================================

typedef struct {
    char broker_url[64];
    int port;
    char topic[64];
    int is_connected;
} MQTTClient;

void MQTT_init(MQTTClient* client, const char* broker, int port, const char* topic) {
    strncpy(client->broker_url, broker, 63);
    client->port = port;
    strncpy(client->topic, topic, 63);
    client->is_connected = 0;
    printf("[MQTT] Client initialized for %s:%d\n", broker, port);
}

int MQTT_connect(MQTTClient* client) {
    /*
     * In real implementation: 
     * - Establish TCP connection to broker
     * - Send MQTT CONNECT packet
     * - Handle CONNACK response
     */
    client->is_connected = 1;
    printf("[MQTT] Connected to broker\n");
    return 0;
}

int MQTT_publish(MQTTClient* client, const char* payload) {
    if (!client->is_connected) {
        printf("[MQTT] ERROR: Not connected to broker\n");
        return -1;
    }

    /*
     * In real implementation:
     * - Send MQTT PUBLISH packet with payload
     * - Handle PUBACK for QoS 1
     */
    printf("[MQTT] Published to %s: %s\n", client->topic, payload);
    return 0;
}

// ============================================
// MAIN APPLICATION (Step 2: Process Specification)
// ============================================

/* Format reading as JSON (Step 4: Information Model) */
void format_reading_as_json(SensorReading* reading, char* output, size_t max_len) {
    snprintf(output, max_len,
        "{\"sensor_id\":\"%s\",\"timestamp\":\"%s\",\"temperature\":%.2f,\"humidity\":%.2f,\"rain_detected\":%d,\"battery\":%.2f}",
        reading->sensor_id,
        reading->timestamp,
        reading->temperature,
        reading->humidity,
        reading->rain_detected,
        reading->battery_level
    );
}

/* Main weather station task */
void weather_station_task(void) {
    printf("\n========================================\n");
    printf("IoT Weather Station - Starting...\n");
    printf("========================================\n\n");

    // Initialize sensors (Step 7: Physical Devices)
    DHT22_Sensor dht22;
    DHT22_init(&dht22, 4);  // GPIO4

    RainSensor rain_sensor;
    RainSensor_init(&rain_sensor, 0, 2000);  // ADC channel 0

    // Initialize MQTT client (Step 5: Communication Services)
    MQTTClient mqtt;
    MQTT_init(&mqtt, "broker.hivemq.com", 1883, "iot/weather/farm001/telemetry");
    MQTT_connect(&mqtt);

    // Device configuration
    DeviceStatus device;
    strcpy(device.device_id, "WS_FARM_001");
    strcpy(device.firmware_version, "1.0.0");
    device.boot_count = 1;
    device.free_heap = 150000;

    // Main loop (Step 2: Process Specification - Data Flow)
    while (1) {
        printf("\n--- Reading Cycle ---\n");

        // Step 2a: Read sensors (Data Flow: Sensor -> Microcontroller)
        DHT22_read(&dht22);
        int rain_status = RainSensor_detect(&rain_sensor);

        // Step 2b: Populate reading structure
        time_t now = time(NULL);
        strftime(device.current_reading.timestamp, 32, "%Y-%m-%dT%H:%M:%SZ", gmtime(&now));

        strcpy(device.current_reading.sensor_id, device.device_id);
        device.current_reading.temperature = dht22.last_temperature;
        device.current_reading.humidity = dht22.last_humidity;
        device.current_reading.rain_detected = rain_status;
        device.current_reading.battery_level = 3.7;  // Simulated battery voltage

        // Print reading
        printf("Temperature: %.2f C\n", device.current_reading.temperature);
        printf("Humidity: %.2f %%\n", device.current_reading.humidity);
        printf("Rain: %s\n", rain_status ? "DETECTED" : "None");

        // Step 2c: Format as JSON and publish
        char json_payload[256];
        format_reading_as_json(&device.current_reading, json_payload, 256);

        // Step 2d: Transmit to cloud (Data Flow: Gateway -> Cloud)
        MQTT_publish(&mqtt, json_payload);

        // Sleep until next reading (30 minute interval = 1800 seconds)
        // In real deployment: deep sleep mode for power efficiency
        printf("\nSleeping for 30 minutes...\n");
        break;  // Exit demo loop
    }

    printf("\n[System] Weather station operational\n");
}

// Entry point
int main(void) {
    srand(time(NULL));  // Seed random generator
    weather_station_task();
    return 0;
}

"""
Information Model Specification - Schema Validation
=====================================================
This module demonstrates Step 4 of IoT Design Methodology:
- Define data schemas (JSON)
- Validate data semantics
- Ensure interoperability between IoT components
"""

import json
from typing import List, Dict, Any, Optional
from dataclasses import dataclass, asdict
from datetime import datetime

# ============================================
# STEP 4: INFORMATION MODEL SPECIFICATION
# ============================================

# JSON Schema for Weather Station Telemetry
# This is the formal Information Model defining data structure and semantics

WEATHER_TELEMETRY_SCHEMA = {
    "$schema": "http://json-schema.org/draft-07/schema#",
    "title": "WeatherStationTelemetry",
    "description": "Information model for weather station sensor data",
    "type": "object",
    "required": ["device_id", "timestamp", "sensors"],
    "properties": {
        "device_id": {
            "type": "string",
            "pattern": "^WS_[A-Z0-9_]+$",
            "description": "Unique identifier for the weather station"
        },
        "timestamp": {
            "type": "string",
            "format": "date-time",
            "description": "ISO 8601 timestamp of reading in UTC"
        },
        "firmware_version": {
            "type": "string",
            "pattern": "^\\d+\\.\\d+\\.\\d+$",
            "description": "Device firmware version"
        },
        "sensors": {
            "type": "array",
            "minItems": 1,
            "items": {
                "type": "object",
                "required": ["sensor_id", "type", "value", "unit"],
                "properties": {
                    "sensor_id": {
                        "type": "string",
                        "description": "Unique sensor identifier"
                    },
                    "type": {
                        "type": "string",
                        "enum": ["temperature", "humidity", "pressure", "wind_speed", "rainfall"],
                        "description": "Semantic meaning of the sensor"
                    },
                    "value": {
                        "type": "number",
                        "description": "Measured value"
                    },
                    "unit": {
                        "type": "string",
                        "description": "Unit of measurement for semantic interoperability"
                    },
                    "accuracy": {
                        "type": "number",
                        "minimum": 0,
                        "description": "Sensor accuracy specification"
                    }
                }
            }
        },
        "location": {
            "type": "object",
            "properties": {
                "latitude": {"type": "number", "minimum": -90, "maximum": 90},
                "longitude": {"type": "number", "minimum": -180, "maximum": 180},
                "altitude": {"type": "number"}
            }
        },
        "metadata": {
            "type": "object",
            "description": "Additional data about the data (provenance, quality)",
            "properties": {
                "battery_level": {"type": "number", "minimum": 0, "maximum": 100},
                "signal_strength": {"type": "number", "minimum": -120, "maximum": 0},
                "data_quality": {"type": "string", "enum": ["good", "suspect", "error"]}
            }
        }
    }
}


# ============================================
# PYTHON DATA CLASSES (Domain + Information Model)
# ============================================

@dataclass
class SensorReading:
    """Domain Model Entity: Individual sensor reading"""
    sensor_id: str
    type: str  # Semantic meaning
    value: float
    unit: str
    accuracy: Optional[float] = None


@dataclass
class DeviceLocation:
    """Domain Model Entity: GPS location"""
    latitude: float
    longitude: float
    altitude: Optional[float] = None


@dataclass
class DeviceMetadata:
    """Metadata about the device and data quality"""
    battery_level: float
    signal_strength: float
    data_quality: str = "good"


@dataclass
class WeatherTelemetry:
    """
    Complete Information Model for Weather Station
    This is the authoritative data schema for the system
    """
    device_id: str
    timestamp: str
    sensors: List[SensorReading]
    firmware_version: Optional[str] = None
    location: Optional[DeviceLocation] = None
    metadata: Optional[DeviceMetadata] = None

    def to_json(self) -> str:
        """Serialize to JSON for transmission"""
        return json.dumps(asdict(self), indent=2)

    @classmethod
    def from_json(cls, json_str: str) -> 'WeatherTelemetry':
        """Deserialize from JSON received from device"""
        data = json.loads(json_str)
        return cls(**data)


# ============================================
# SCHEMA VALIDATION IMPLEMENTATION
# ============================================

class InformationModelValidator:
    """
    Validates incoming IoT data against the Information Model
    Ensures semantic interoperability across the system
    """

    def __init__(self, schema: Dict[str, Any]):
        self.schema = schema
        self.errors: List[str] = []

    def validate(self, data: Dict[str, Any]) -> bool:
        """
        Validate data against schema
        Returns True if valid, False otherwise
        """
        self.errors = []

        # Check required fields
        for required_field in self.schema.get("required", []):
            if required_field not in data:
                self.errors.append(f"Missing required field: {required_field}")

        # Validate sensor readings
        if "sensors" in data:
            valid_types = ["temperature", "humidity", "pressure", "wind_speed", "rainfall"]
            for i, sensor in enumerate(data["sensors"]):
                if "type" in sensor and sensor["type"] not in valid_types:
                    self.errors.append(f"Sensor {i}: Invalid type '{sensor['type']}'")

                # Validate temperature range
                if sensor.get("type") == "temperature":
                    if not -50 <= sensor.get("value", 0) <= 60:
                        self.errors.append(f"Sensor {i}: Temperature out of valid range (-50 to 60)")

                # Validate humidity range
                if sensor.get("type") == "humidity":
                    if not 0 <= sensor.get("value", 0) <= 100:
                        self.errors.append(f"Sensor {i}: Humidity out of valid range (0 to 100)")

        # Validate location coordinates
        if "location" in data:
            loc = data["location"]
            if not -90 <= loc.get("latitude", 0) <= 90:
                self.errors.append("Invalid latitude: must be between -90 and 90")
            if not -180 <= loc.get("longitude", 0) <= 180:
                self.errors.append("Invalid longitude: must be between -180 and 180")

        return len(self.errors) == 0

    def get_errors(self) -> List[str]:
        """Return list of validation errors"""
        return self.errors


# ============================================
# DEMONSTRATION
# ============================================

def demonstrate_information_model():
    """
    Demonstrate the Information Model specification
    following Step 4 of IoT Design Methodology
    """

    print("=" * 70)
    print("IoT Design Methodology - Step 4: Information Model Specification")
    print("=" * 70)

    # Create a valid telemetry message
    print("\n[1] Creating Weather Station Telemetry (Valid Data):")
    print("-" * 50)

    telemetry = WeatherTelemetry(
        device_id="WS_FARM_001",
        timestamp=datetime.utcnow().isoformat() + "Z",
        firmware_version="1.2.0",
        sensors=[
            SensorReading(sensor_id="TEMP_01", type="temperature", value=25.5, unit="celsius", accuracy=0.5),
            SensorReading(sensor_id="HUM_01", type="humidity", value=65.0, unit="percent", accuracy=2.0),
            SensorReading(sensor_id="RAIN_01", type="rainfall", value=0.0, unit="mm", accuracy=0.1)
        ],
        location=DeviceLocation(latitude=13.0827, longitude=80.2707, altitude=45.0),
        metadata=DeviceMetadata(battery_level=85.5, signal_strength=-72.0)
    )

    print(telemetry.to_json())

    # Validate the telemetry
    print("\n[2] Validating against Information Model Schema:")
    print("-" * 50)

    validator = InformationModelValidator(WEATHER_TELEMETRY_SCHEMA)
    data_dict = json.loads(telemetry.to_json())

    if validator.validate(data_dict):
        print("✓ Validation PASSED - Data conforms to Information Model")
    else:
        print("✗ Validation FAILED:", validator.get_errors())

    # Demonstrate invalid data detection
    print("\n[3] Testing with Invalid Data (Detecting anomalies):")
    print("-" * 50)

    invalid_telemetry = WeatherTelemetry(
        device_id="WS_FARM_001",
        timestamp=datetime.utcnow().isoformat() + "Z",
        sensors=[
            SensorReading(sensor_id="TEMP_01", type="temperature", value=150.0, unit="celsius"),  # Invalid!
            SensorReading(sensor_id="HUM_01", type="humidity", value=-10.0, unit="percent")  # Invalid!
        ]
    )

    validator2 = InformationModelValidator(WEATHER_TELEMETRY_SCHEMA)
    invalid_dict = json.loads(invalid_telemetry.to_json())

    if validator2.validate(invalid_dict):
        print("✓ Validation PASSED")
    else:
        print("✗ Validation FAILED - Detected errors:")
        for error in validator2.get_errors():
            print(f"  - {error}")

    print("\n" + "=" * 70)
    print("Information Model ensures semantic interoperability!")
    print("=" * 70)


if __name__ == "__main__":
    demonstrate_information_model()
